namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

public static class RecipeStore
{
    private static int _nextId = 7;

    public static List<Recipe> Recipes { get; } =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = [
                "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                "Stretch dough into a 12-inch round on a floured surface.",
                "Spread crushed tomatoes evenly, leaving a 1-inch border.",
                "Tear mozzarella into pieces and distribute over the sauce.",
                "Bake for 10–12 minutes until the crust is golden.",
                "Top with fresh basil and a drizzle of olive oil."
            ],
            TotalRatings = 12, RatingSum = 52
        },
        new()
        {
            Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a creamy, spiced tomato sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
            Steps = [
                "Marinate chicken in yogurt, garam masala, and salt for 1 hour.",
                "Grill or pan-sear the chicken until charred and cooked through.",
                "Sauté onion, garlic, and ginger in a large pan.",
                "Add spices and tomato sauce; simmer for 15 minutes.",
                "Stir in cream and the cooked chicken. Simmer 10 more minutes.",
                "Serve over basmati rice with naan bread."
            ],
            TotalRatings = 8, RatingSum = 38
        },
        new()
        {
            Id = 3, Title = "Beef Tacos", Category = "Mexican",
            Description = "Flavorful ground beef tacos with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = [
                "Brown ground beef in a skillet over medium-high heat.",
                "Add taco seasoning and water; simmer until thickened.",
                "Warm tortillas in a dry skillet or microwave.",
                "Fill tortillas with seasoned beef.",
                "Top with lettuce, tomato, cheese, sour cream, and salsa."
            ],
            TotalRatings = 15, RatingSum = 63
        },
        new()
        {
            Id = 4, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Rich and creamy pasta with pancetta and Parmesan.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper", "Salt"],
            Steps = [
                "Cook spaghetti in salted boiling water until al dente.",
                "Crisp pancetta in a skillet until golden.",
                "Whisk eggs, Parmesan, and pepper in a bowl.",
                "Toss hot pasta with pancetta, then remove from heat.",
                "Quickly stir in the egg mixture, tossing to coat without scrambling.",
                "Serve immediately with extra Parmesan."
            ],
            TotalRatings = 10, RatingSum = 45
        },
        new()
        {
            Id = 5, Title = "Vegetable Stir Fry", Category = "Asian",
            Description = "A quick and healthy vegetable stir fry with soy sauce and ginger.",
            Ingredients = ["Broccoli", "Bell pepper", "Snap peas", "Carrots", "Soy sauce", "Sesame oil", "Garlic", "Ginger", "Rice"],
            Steps = [
                "Cook rice according to package instructions.",
                "Heat sesame oil in a wok over high heat.",
                "Add garlic and ginger; stir for 30 seconds.",
                "Add vegetables and stir-fry for 4–5 minutes until crisp-tender.",
                "Pour in soy sauce, toss to coat, and serve over rice."
            ],
            TotalRatings = 6, RatingSum = 25
        },
        new()
        {
            Id = 6, Title = "Chocolate Chip Cookies", Category = "Desserts",
            Description = "Classic chewy chocolate chip cookies.",
            Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla", "Flour", "Baking soda", "Salt", "Chocolate chips"],
            Steps = [
                "Preheat oven to 375°F (190°C).",
                "Cream butter and sugars until light and fluffy.",
                "Beat in eggs and vanilla.",
                "Mix in flour, baking soda, and salt until just combined.",
                "Fold in chocolate chips.",
                "Drop rounded tablespoons onto baking sheets.",
                "Bake for 9–11 minutes until edges are golden."
            ],
            TotalRatings = 20, RatingSum = 92
        }
    ];

    public static List<string> Categories =>
        Recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public static void AddRecipe(RecipeSubmission submission)
    {
        Recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        });
    }
}

@using RecipeCommunity.Models

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= DisplayRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              title="Rate @star star(s)">
            @(star <= DisplayRating ? "★" : "☆")
        </span>
    }
    @if (Recipe.TotalRatings > 0)
    {
        <span class="rating-info">
            @Recipe.AverageRating.ToString("0.0") avg · @Recipe.TotalRatings ratings
        </span>
    }
    @if (_userRating.HasValue)
    {
        <span class="user-feedback">You rated this @_userRating ★</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Recipe Recipe { get; set; } = default!;

    private int? _userRating;

    private int DisplayRating => _userRating ?? (int)Math.Round(Recipe.AverageRating);

    private void Rate(int stars)
    {
        if (_userRating.HasValue)
            return;

        _userRating = stars;
        Recipe.RatingSum += stars;
        Recipe.TotalRatings++;
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 2px;
    margin: 0.75rem 0;
}

.star {
    font-size: 1.6rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s;
    user-select: none;
}

.star:hover,
.star.filled {
    color: #f5a623;
}

.rating-info {
    margin-left: 0.75rem;
    font-size: 0.9rem;
    color: #666;
}

.user-feedback {
    margin-left: 0.5rem;
    font-size: 0.85rem;
    color: #28a745;
    font-weight: 500;
}

