arguments.file_text:
@page "/recipes/{Category}"
@using RecipeCommunity.Models

<PageTitle>@Category Recipes — Recipe Community</PageTitle>

<h1>@CategoryEmoji @Category Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">@recipe.Description</p>
                        @if (recipe.TotalRatings > 0)
                        {
                            <small class="text-warning">
                                @(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))
                                (@recipe.AverageRating.ToString("0.0"))
                            </small>
                        }
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="recipe/@recipe.Id" class="btn btn-sm btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    private string CategoryEmoji => Category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥢",
        "Desserts" => "🍪",
        _ => "🍽️"
    };

    protected override void OnParametersSet()
    {
        _recipes = RecipeStore.Recipes
            .Where(r => r.Category.Equals(Category, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Models

<PageTitle>@(_recipe?.Title ?? "Recipe") — Recipe Community</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (_recipe is not null)
        {
            <li class="breadcrumb-item"><a href="recipes/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        }
    </ol>
</nav>

@if (_recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@_recipe.Title</h1>
    <p class="lead text-muted">@_recipe.Description</p>

    <StarRating Recipe="_recipe" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header fw-bold">🧾 Ingredients</div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h4>📝 Instructions</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in _recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeStore.Recipes.FirstOrDefault(r => r.Id == Id);
    }
}

@page "/submit"
@using RecipeCommunity.Models
@rendermode InteractiveServer

<PageTitle>Submit a Recipe — Recipe Community</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added. <a href="recipes/@_model.Category">View it in @_model.Category recipes</a>.</p>
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit another</button>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-bold">Recipe Title</label>
                    <InputText @bind-Value="_model.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-bold">Category</label>
                    <InputSelect @bind-Value="_model.Category" class="form-select">
                        <option value="">— Select a category —</option>
                        <option value="Italian">Italian</option>
                        <option value="Indian">Indian</option>
                        <option value="Mexican">Mexican</option>
                        <option value="Asian">Asian</option>
                        <option value="Desserts">Desserts</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label fw-bold">Ingredients</label>
                    <InputTextArea @bind-Value="_model.Ingredients" class="form-control" rows="6"
                        placeholder="One ingredient per line&#10;e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label class="form-label fw-bold">Steps</label>
                    <InputTextArea @bind-Value="_model.Steps" class="form-control" rows="6"
                        placeholder="One step per line&#10;e.g.&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients and stir" />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                <button type="submit" class="btn btn-success btn-lg"
                    disabled="@(!IsValid)">
                    Submit Recipe
                </button>
            </div>
        </div>
    </EditForm>
}

@code {
    private RecipeSubmission _model = new();
    private bool _submitted;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(_model.Title) &&
        !string.IsNullOrWhiteSpace(_model.Category) &&
        !string.IsNullOrWhiteSpace(_model.Ingredients) &&
        !string.IsNullOrWhiteSpace(_model.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeStore.AddRecipe(_model);
        _submitted = true;
    }

    private void Reset()
    {
        _model = new RecipeSubmission();
        _submitted = false;
    }
}

